async (params, browser) => {
  // Open person page
  await browser.open(`${params.person_url}`)

  // Wait for page to load
  await browser.waitForSelector('[data-testid=\'hero-title-block__title\'], [data-testid=\'hero__pageTitle\'], h1, [class*=\'NameHeader\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load filmography
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract person profile
  const person_data = await browser.evaluate(`const nameEl = document.querySelector('[data-testid="hero-title-block__title"], [data-testid="hero__pageTitle"] span, h1 span, h1, [class*="NameHeader"] h1'); const bioEl = document.querySelector('[data-testid="bio-content"], [class*="bio"] p, .ipc-html-content-inner-div'); const photoEl = document.querySelector('[data-testid="hero-media__photo"] img, [data-testid="hero__photo"] img, [class*="Poster"] img, #name-poster'); const birthInfoEl = document.querySelector('[data-testid="birth-and-death-info"], [class*="birth"]'); const knownFor = []; document.querySelectorAll('[data-testid="nm-flmg-known-for-card"], [class*="KnownFor"] [class*="KnownForCard"]').forEach(function(el) { const titleEl = el.querySelector('a[href*="/title/"], [class*="title"]'); const yearEl = el.querySelector('[class*="year"], span'); const roleEl = el.querySelector('[class*="role"], [class*="character"]'); const imgEl = el.querySelector('img'); knownFor.push({ title: titleEl ? titleEl.textContent.trim() : '', year: yearEl ? yearEl.textContent.trim() : '', role: roleEl ? roleEl.textContent.trim() : '', url: titleEl ? titleEl.href || '' : '', image: imgEl ? imgEl.getAttribute('src') : '' }); }); const filmography = []; const filmEls = document.querySelectorAll('[data-testid="nm-flmg-credits-single-item"], [class*="FilmographyItem"], [class*="filmography"] [class*="row"]'); for (let i = 0; i < Math.min(filmEls.length, 20); i++) { const el = filmEls[i]; const tEl = el.querySelector('a[href*="/title/"], [class*="title"]'); const yEl = el.querySelector('[class*="year"]'); filmography.push({ title: tEl ? tEl.textContent.trim() : '', year: yEl ? yEl.textContent.trim() : '', url: tEl ? tEl.href || '' : '' }); } const awardsEl = document.querySelector('[data-testid="awards-summary"], [class*="Awards"]'); return { name: nameEl ? nameEl.textContent.trim() : '', bio: bioEl ? bioEl.textContent.trim().substring(0, 1500) : '', photo: photoEl ? photoEl.getAttribute('src') : '', birth_info: birthInfoEl ? birthInfoEl.textContent.trim() : '', known_for: knownFor.slice(0, 6), filmography: filmography, awards: awardsEl ? awardsEl.textContent.trim().substring(0, 500) : '', url: window.location.href }`)

  return person_data
}
